  roman:'\\🏛 Roman & Wall History', wildlife:'\\🦅 Wildlife & Nature',
  architecture:'\\🏚 Architecture & Local History', pubs:'\\🍺 Pubs, Food & Stops',
  dark_humour:'\\⚰ Dark Hiking Humour', film_tv:'\\🎬 Film & TV',
