// ── ESTIMATION BATTLE ────────────────────────────────────────────
var currentEST = null;
function showEstimation() {
  hideAllCards();
  document.getElementById('quiz-empty').style.display = 'none';
  var item = EST[Math.floor(Math.random() * EST.length)];
  currentEST = item;
  document.getElementById('est-card').style.display = 'block';
  document.getElementById('est-text').textContent = item.text;
  document.getElementById('est-result').classList.remove('show');
  document.getElementById('est-p1').value = '';
  document.getElementById('est-p2').value = '';
  document.getElementById('est-submit').style.display = 'inline-block';

  // Update player labels on inputs
  if (myPlayer) {
    var p1 = myPlayer === 'telemicus' ? 'Telemicus' : 'Ivanhoe';
    var p2 = myPlayer === 'telemicus' ? 'Ivanhoe' : 'Telemicus';
    document.querySelector('#est-card div:nth-child(4) > div:first-child > div:first-child').textContent = p1;
    document.querySelector('#est-card div:nth-child(4) > div:last-child > div:first-child').textContent = p2;
  }
}

function submitEstimation() {
  if (!currentEST) return;
  var g1 = parseInt(document.getElementById('est-p1').value) || 0;
  var g2 = parseInt(document.getElementById('est-p2').value) || 0;
  var actual = currentEST.answer;
  var diff1 = Math.abs(g1 - actual);
  var diff2 = Math.abs(g2 - actual);

  var winner = diff1 < diff2 ? 1 : (diff2 < diff1 ? 2 : 0);
  if (winner === 1) state.p1 += 2;
  if (winner === 2) state.p2 += 2;

  state.history.push({ id:'est-' + Date.now(), player:winner, correct:winner > 0, points:2, time:0, ts:Date.now() });
  saveState();

  var p1Name = myPlayer === 'telemicus' ? 'Telemicus' : 'Ivanhoe';
  var p2Name = myPlayer === 'telemicus' ? 'Ivanhoe' : 'Telemicus';
  var resultText = 'Answer: ' + actual + (currentEST.unit ? ' ' + currentEST.unit : '') + '. ';
  resultText += p1Name + ' guessed ' + g1 + ' (off by ' + diff1 + '). ';
  resultText += p2Name + ' guessed ' + g2 + ' (off by ' + diff2 + '). ';
  if (winner === 1) resultText += p1Name + ' wins! +2 points.';
  else if (winner === 2) resultText += p2Name + ' wins! +2 points.';
  else resultText += 'Dead heat!';
  resultText += ' ' + currentEST.fact;

  document.getElementById('est-result').textContent = resultText;
  document.getElementById('est-result').classList.add('show');
  document.getElementById('est-submit').style.display = 'none';
  document.getElementById('next-q').style.display = 'inline-block';
  document.getElementById('score-p1').textContent = state.p1;
  document.getElementById('score-p2').textContent = state.p2;
  currentEST = null;
}

function showQuestion(q) {
  currentQuestion = q;
  questionStartTime = Date.now();
  document.getElementById('quiz-empty').style.display = 'none';
  document.getElementById('quiz-card').style.display = 'block';
  document.getElementById('next-q').style.display = 'none';
  document.getElementById('char-comment').classList.remove('show');

  var catLabel = CATS[q.cat] || q.cat;
  document.getElementById('q-cat').textContent = catLabel;

  if (q.stop && STOPS[q.stop]) {
    var s = STOPS[q.stop];
    document.getElementById('q-loc').textContent = '\\📍 ' + s.name + (s.romanName ? ' (' + s.romanName + ')' : '');
    document.getElementById('q-loc').style.display = 'block';
  } else {
    document.getElementById('q-loc').style.display = 'none';
  }

  document.getElementById('q-text').textContent = q.text;
  document.getElementById('q-fact').textContent = q.fact;
  document.getElementById('q-fact').classList.remove('show');

  var optsDiv = document.getElementById('q-opts');
  optsDiv.innerHTML = '';
  for (var i = 0; i < q.opts.length; i++) {
    var btn = document.createElement('div');
    btn.className = 'q-opt';
    btn.textContent = q.opts[i];
    btn.setAttribute('data-idx', i);
    btn.onclick = function() { handleAnswer(parseInt(this.getAttribute('data-idx'))); };
    optsDiv.appendChild(btn);
  }

  document.getElementById('score-p1').textContent = state.p1;
  document.getElementById('score-p2').textContent = state.p2;
}

function handleAnswer(idx) {
  if (!currentQuestion) return;
  var q = currentQuestion;

  // Prevent double-click
  var opts = document.querySelectorAll('.q-opt');
  for (var i = 0; i < opts.length; i++) {
    opts[i].onclick = null;
  }

  var timeMs = Date.now() - questionStartTime;
  var correct = idx === q.ans;
  var points = correct ? (timeMs < 5000 ? 3 : timeMs < 15000 ? 2 : 1) : 0;

  // Highlight correct/wrong
  opts[q.ans].classList.add('correct');
  if (!correct) opts[idx].classList.add('wrong');

  // Score for current player
  if (correct) {
    if (state.currentPlayer === 1) state.p1 += points;
    else state.p2 += points;
  }

  // Record
  state.answered.push(q.id);
  state.history.push({ id:q.id, player:state.currentPlayer, correct:correct, points:points, time:timeMs, ts:Date.now() });

  // Toggle player
  state.currentPlayer = state.currentPlayer === 1 ? 2 : 1;
  saveState();

  // Show fact
  document.getElementById('q-fact').classList.add('show');

  // Character quip
  var quips = correct ? CHAR_QUIPS.correct : CHAR_QUIPS.wrong;
  var quip = quips[Math.floor(Math.random() * quips.length)];
  document.getElementById('char-name').textContent = quip.char;
  document.getElementById('char-text').textContent = quip.text;
  document.getElementById('char-comment').classList.add('show');

  // Update scores
  document.getElementById('score-p1').textContent = state.p1;
  document.getElementById('score-p2').textContent = state.p2;

  // Show next button + react button
  document.getElementById('next-q').style.display = 'inline-block';
  document.getElementById('react-btn').style.display = 'inline-block';
  document.getElementById('react-results').style.display = 'none';
  document.getElementById('react-results').innerHTML = '';
  lastAnsweredFact = q.fact + ' (Question: ' + q.text + ')';
  currentQuestion = null;
}

function nextQuestion() {
  if (questionQueue.length > 0) {
    showQuestion(questionQueue.shift());
  } else {
    loadGeneralQuestion();
  }
}

